const AWS = require('aws-sdk');
const { exec } = require('child_process');
const s3 = new AWS.S3();

exports.handler = async (event) => {
    const bucket = event.Records[0].s3.bucket.name;
    const key = decodeURIComponent(event.Records[0].s3.object.key.replace(/\+/g, ' '));
    const outputFormat = event.Records[0].s3.object.metadata.outputFormat;
    
    const inputFilePath = `/tmp/${key}`;
    const outputFileName = key.split('.').slice(0, -1).join('.') + `.${outputFormat}`;
    const outputFilePath = `/tmp/${outputFileName}`;

    try {
        await downloadImage(bucket, key, inputFilePath);
        await convertImage(inputFilePath, outputFilePath, outputFormat);
        await uploadImage(bucket, outputFileName, outputFilePath);
        return { statusCode: 200, body: 'Image converted successfully' };
    } catch (err) {
        console.error(err);
        return { statusCode: 500, body: 'Image conversion failed' };
    }
};

function downloadImage(bucket, key, downloadPath) {
    return new Promise((resolve, reject) => {
        const params = { Bucket: bucket, Key: key };
        const fileStream = require('fs').createWriteStream(downloadPath);

        s3.getObject(params)
            .createReadStream()
            .pipe(fileStream)
            .on('finish', resolve)
            .on('error', reject);
    });
}

function convertImage(inputPath, outputPath, format) {
    return new Promise((resolve, reject) => {
        const command = `convert "${inputPath}" "${outputPath}"`;
        exec(command, (error, stdout, stderr) => {
            if (error) {
                reject(`Error: ${stderr}`);
            } else {
                resolve(stdout);
            }
        });
    });
}

function uploadImage(bucket, key, uploadPath) {
    return new Promise((resolve, reject) => {
        const fileStream = require('fs').createReadStream(uploadPath);
        const params = {
            Bucket: bucket,
            Key: key,
            Body: fileStream,
            ContentType: `image/${key.split('.').pop()}`
        };

        s3.upload(params, (err, data) => {
            if (err) {
                reject(err);
            } else {
                resolve(data);
            }
        });
    });
}